class Solution:
    def leastOpsExpressTarget(self, x: int, target: int) -> int:
        if x == target:
            return 0
        if x > target:
            return (target + x - 1) // x

        ops = float('inf')
        cur = 1
        div = 0
        while cur <= target:
            if target % cur == 0:
                ops = min(ops, div + target // cur - 1)
            cur *= x
            div += 1

        cur = x
        add = 1
        while cur <= target:
            if (target - cur) % x == 0:
                ops = min(ops, add + (target - cur) // x)
            cur *= x
            add += 1

        return ops

